"""Bundled cursor-sdk-bridge resolver.

Platform-specific wheels stage a hermetic bridge tree under
``cursor_sdk/_vendor/bridge/`` at build time; this module finds the
launcher inside that tree and falls back to the system PATH for
developers running from source.

Resolution order (first match wins):

1. ``CURSOR_SDK_BRIDGE_BIN`` env var (absolute path to a launcher).
2. The bundled launcher under ``cursor_sdk/_vendor/bridge/bin/``.
3. ``cursor-sdk-bridge`` on ``PATH`` (legacy, dev-mode, or when the
   user opts out of the bundled binary via
   ``CURSOR_SDK_USE_REMOTE_BRIDGE=1``).

Keep this module dependency-free at import time so it stays cheap to
import from ``_bridge.py`` and ``_async_bridge.py``.
"""

from __future__ import annotations

import os
import shutil
import stat
import sys
from collections.abc import Iterator
from pathlib import Path

from ..errors import CursorSDKError

_LAUNCHER_NAME_POSIX = "cursor-sdk-bridge"
_LAUNCHER_NAME_WIN = "cursor-sdk-bridge.cmd"
_USE_REMOTE_BRIDGE_ENV = "CURSOR_SDK_USE_REMOTE_BRIDGE"
_BRIDGE_BIN_OVERRIDE_ENV = "CURSOR_SDK_BRIDGE_BIN"

# `bridge/` is staged as a plain data directory next to this file by
# scripts/build_wheel.py; it has no `__init__.py` (and shouldn't, the
# files inside aren't importable). We resolve it via __file__ instead
# of `importlib.resources.files("cursor_sdk._vendor.bridge")`, because
# the latter rejects namespace packages on Python 3.10/3.11 with a
# `TypeError`.
_BRIDGE_DIR = Path(__file__).resolve().parent / "bridge"


def _launcher_filename() -> str:
    return _LAUNCHER_NAME_WIN if sys.platform == "win32" else _LAUNCHER_NAME_POSIX


def _bundled_launcher_path() -> Path | None:
    """Return the bundled launcher path if the wheel staged it, else None."""
    path = _BRIDGE_DIR / "bin" / _launcher_filename()
    return path if path.is_file() else None


def _opted_out_of_bundled() -> bool:
    value = os.environ.get(_USE_REMOTE_BRIDGE_ENV, "")
    return value.strip().lower() in {"1", "true", "yes", "on"}


def _ensure_executable(path: Path) -> None:
    """Make the launcher executable on POSIX if the install dropped the bit.

    Some wheel installers (older pip, custom unpackers) strip the
    executable bit when extracting binary data. Restore it idempotently
    so we never crash with a permission error during ``Bridge.launch``.
    """
    if sys.platform == "win32":
        return
    try:
        current = path.stat().st_mode
    except OSError:
        return
    desired = current | stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH
    if desired != current:
        try:
            path.chmod(desired)
        except OSError:
            # Best-effort: subprocess.Popen will raise a clear error if
            # the bit is still missing; we don't want a chmod failure
            # to mask a real permissions problem.
            pass


def resolve_bridge_path() -> str:
    """Return the absolute path or PATH-name for the cursor-sdk-bridge launcher.

    Raises ``CursorSDKError`` with a clear message if no bridge can be
    located. Callers pass the returned value as ``Bridge.launch(command=...)``.
    """
    override = os.environ.get(_BRIDGE_BIN_OVERRIDE_ENV, "").strip()
    if override:
        path = Path(override).expanduser()
        if not path.is_file():
            raise CursorSDKError(
                f"{_BRIDGE_BIN_OVERRIDE_ENV}={override!r} does not point to a file."
            )
        _ensure_executable(path)
        return str(path)

    if not _opted_out_of_bundled():
        bundled = _bundled_launcher_path()
        if bundled is not None:
            _ensure_executable(bundled)
            return str(bundled)

    on_path = _find_bridge_on_path()
    if on_path:
        return on_path

    raise CursorSDKError(
        "Unable to locate cursor-sdk-bridge. Install the cursor-sdk wheel "
        "(which bundles the bridge for your platform), set "
        f"{_BRIDGE_BIN_OVERRIDE_ENV} to an absolute launcher path, or place "
        "cursor-sdk-bridge on PATH."
    )


def _find_bridge_on_path() -> str | None:
    for candidate in _path_candidates(_LAUNCHER_NAME_POSIX):
        if _is_self_console_script(candidate) or _is_package_console_script(candidate):
            continue
        return candidate
    return None


def _path_candidates(name: str) -> Iterator[str]:
    for entry in os.environ.get("PATH", "").split(os.pathsep):
        candidate = shutil.which(name, path=entry or os.curdir)
        if candidate:
            yield candidate


def _is_package_console_script(candidate: str) -> bool:
    try:
        path = Path(candidate)
        if not path.is_file():
            return False
        contents = path.read_text(encoding="utf-8", errors="ignore")
    except OSError:
        return False
    return "cursor_sdk._vendor" in contents and "console_entry" in contents


def console_entry() -> "int | None":
    """``cursor-sdk-bridge`` console script: exec the bundled launcher with argv."""
    bridge = resolve_bridge_path()
    # Self-loop guard: when the bundled bridge is missing,
    # resolve_bridge_path()'s PATH fallback returns this same console
    # script, which would os.execv-loop on POSIX or fork-bomb on Windows.
    if _is_self_console_script(bridge):
        raise CursorSDKError(
            "cursor-sdk-bridge resolved to this console script (a wheel-install "
            "loop). The bundled bridge under cursor_sdk/_vendor/bridge/ is "
            "missing or damaged. Reinstall cursor-sdk, or set "
            f"{_BRIDGE_BIN_OVERRIDE_ENV} to a separate bridge launcher."
        )
    args = [bridge, *sys.argv[1:]]
    if sys.platform == "win32":
        # os.execv on Windows has surprising semantics around
        # subprocess inheritance; spawn-and-wait keeps signal handling
        # and exit codes predictable.
        import subprocess

        completed = subprocess.run(args, check=False)
        return completed.returncode
    os.execv(bridge, args)


def _is_self_console_script(candidate: str) -> bool:
    """True if ``candidate`` resolves to the same file we were invoked from.

    ``sys.argv[0]`` for a pip-installed console script is the absolute
    path to the generated entry-point launcher (e.g.
    ``<venv>/bin/cursor-sdk-bridge``). Compare via ``os.path.realpath``
    so symlinked venv layouts still match.
    """
    try:
        candidate_real = os.path.realpath(candidate)
        self_real = os.path.realpath(sys.argv[0]) if sys.argv else ""
    except OSError:
        return False
    return bool(self_real) and candidate_real == self_real


__all__ = ["console_entry", "resolve_bridge_path"]
